import logging
import json
import traceback

class JsonFormatter(logging.Formatter):
    def __init__(self, fmt=None, datefmt=None, style='%', json_indent=None, **kwargs):
        super().__init__(fmt, datefmt, style)
        self.json_indent = json_indent
        self.default_attrs = {
            'level': 'levelname',
            'logger_name': 'name',
            'timestamp': 'asctime',
            'message': 'message',
            'func_name': 'funcName',
            'line_no': 'lineno',
            'file_path': 'pathname',
            'process_id': 'process',
            'thread_id': 'thread',
            'exception': 'exc_info',
            'stack_trace': 'stack_info',
        }
        # Allow overriding default attributes or adding new ones
        self.extra_attrs = kwargs

    def format(self, record):
        log_record = {}

        # Populate default attributes
        for key, attr_name in self.default_attrs.items():
            if attr_name == 'asctime':
                log_record[key] = self.formatTime(record, self.datefmt)
            elif attr_name == 'exc_info':
                if record.exc_info:
                    log_record[key] = self.formatException(record.exc_info)
            elif attr_name == 'stack_info':
                if record.stack_info:
                    log_record[key] = self.formatStack(record.stack_info)
            elif hasattr(record, attr_name):
                value = getattr(record, attr_name)
                # Ensure message is always formatted first
                if attr_name == 'message':
                    log_record[key] = record.getMessage()
                elif value is not None:
                    log_record[key] = value

        # Add any extra attributes from the record's __dict__
        # This includes custom attributes added via `logger.info("msg", extra={"key": "value"})`
        for key, value in record.__dict__.items():
            if key not in ['name', 'msg', 'levelname', 'levelno', 'pathname', 'filename',
                           'module', 'exc_info', 'exc_text', 'stack_info', 'lineno',
                           'funcName', 'created', 'msecs', 'relativeCreated', 'thread',
                           'threadName', 'processName', 'process', 'args', 'asctime',
                           'message', 'extra'] and not key.startswith('_'): # Exclude internal logger attributes
                if key not in log_record: # Don't overwrite default/predefined keys
                    log_record[key] = value

        # Add/override with attributes from self.extra_attrs
        for key, attr_name in self.extra_attrs.items():
            if hasattr(record, attr_name):
                log_record[key] = getattr(record, attr_name)

        try:
            return json.dumps(log_record, indent=self.json_indent, ensure_ascii=False)
        except TypeError as e:
            # Fallback if json serialization fails for some reason
            log_record['json_serialization_error'] = str(e)
            return json.dumps(log_record, indent=self.json_indent, ensure_ascii=False)

